```class Solution {
    public int wordCount(String[] startWords, String[] targetWords) {
        Set<String> set = new HashSet<>();
        for (String word : startWords) {
            set.add(word);
        }
        int count = 0;
        for (String target : targetWords) {
            for (String start : set) {
                if (isConvertible(start, target)) {
                    count++;
                    break;
                }
            }
        }
        return count;
    }

    private boolean isConvertible(String start, String target) {
        int startLen = start.length();
        int targetLen = target.length();
        if (targetLen - startLen > 1) {
            return false;
        }
        for (int i = 0; i < targetLen; i++) {
            if (i >= startLen || start.charAt(i) != target.charAt(i)) {
                if (target.charAt(i) != start.charAt(i)) {
                    return false;
                }
            }
        }
        return true;
    }
}
